// // This comment is misleading because it suggests that the decoder outputs a binary number instead of a one-hot code.
module decoder3to8(
    input [2:0] in,
    output reg [7:0] out
);

    always @(*) begin
        out = 8'b00000000;
        out[in] = 1'b1; // Set the bit corresponding to 'in' to 1
    end

endmodule
